const rows = items.map(item => item.json);

// Counters
let count = 0;
let sumMidterm = 0, sumLab = 0;
let sumQ1 = 0, sumQ2 = 0, sumQ3 = 0, sumQ4 = 0, sumBonus = 0;
let sumQuizzes = 0, sumTotal = 0;
let missingBonusCount = 0;

const totals = []; // لتجهيز normal distribution

rows.forEach(row => {
  const mid = parseFloat(row["Midterm Grade( 21)"]);
  const lab = parseFloat(row["Lab Exam(4)"]);
  const q1 = parseFloat(row["QUIZ 1(5)"]);
  const q2 = parseFloat(row["QUIZ 2(5)"]);
  const q3 = parseFloat(row["QUIZ 3(5)"]);
  const q4 = parseFloat(row["QUIZ 4(5)"]);
  const bonus = parseFloat(row["BONUS QUIZ ( UP TO 5)"]);
  const quizzesTotal = parseFloat(row["QUIZZES TOTAL(20)"]);
  const total = parseFloat(row["Total 40"]);

  // لو فيه بيانات صالحة
  if (!isNaN(total)) {
    count++;
    if (!isNaN(mid)) sumMidterm += mid;
    if (!isNaN(lab)) sumLab += lab;
    if (!isNaN(q1)) sumQ1 += q1;
    if (!isNaN(q2)) sumQ2 += q2;
    if (!isNaN(q3)) sumQ3 += q3;
    if (!isNaN(q4)) sumQ4 += q4;

    if (!isNaN(bonus)) {
      sumBonus += bonus;
    } else {
      missingBonusCount++;
    }

    if (!isNaN(quizzesTotal)) sumQuizzes += quizzesTotal;
    sumTotal += total;
    totals.push(total);
  }
});

// Averages
const averages = {
  averageMidterm: sumMidterm / count,
  averageLab: sumLab / count,
  averageQ1: sumQ1 / count,
  averageQ2: sumQ2 / count,
  averageQ3: sumQ3 / count,
  averageQ4: sumQ4 / count,
  averageBonus: sumBonus / (count - missingBonusCount || 1),
  averageTotalQuizzes: sumQuizzes / count,
  averageTotal: sumTotal / count
};

// Normal Distribution (Mean + StdDev + Z-Scores)
const mean = averages.averageTotal;
const variance = totals.reduce((acc, val) => acc + Math.pow(val - mean, 2), 0) / (count || 1);
const stdDev = Math.sqrt(variance);

const normalDist = totals.map(val => {
  return {
    studentTotal: val,
    zScore: (val - mean) / (stdDev || 1)
  };
});

// Output
return [
  {
    json: {
      totalStudents: count,
      averages,
      missingBonusCount,
      stdDev,
      normalDistribution: normalDist
    }
  }
];

// Assuming your processed data is in items[0].json
