    averageMidterm: $input.first().json.averages.averageMidterm,
    averageLab: $input.first().json.averages.averageLab,
    averageQ1: $input.first().json.averages.averageQ1,
    averageQ2: $input.first().json.averages.averageQ2,
    averageQ3: $input.first().json.averages.averageQ3,
    averageQ4: $input.first().json.averages.averageQ4,
    averageBonus: $input.first().json.averages.averageBonus,
    averageTotalQuizzes: $input.first().json.averages.averageTotalQuizzes,
    averageTotal: $input.first().json.averages.averageTotal,
    missingBonusCount: data.missingBonusCount,
    stdDev: data.stdDev
  }
}];

